inputs.value:
@trim(
  replace(
    replace(
      replace(
        coalesce(
          body('Parse_OCR_Success_JSON_Response')?['VendorName'],
          'UnknownVendor'
        ),
        '''',
        ''
      ),
      decodeUriComponent('%0A'),
      ' '
    ),
    decodeUriComponent('%0D'),
    ' '
  )
)

Winner.inputs:
@first(
  if(
    and(
      not(empty(variables('CompanyCode'))),
      greater(length(body('ByCompany')), 0)
    ),
    body('ByCompany'),
    body('ParseVendors')?['value']
  )
)

Winner1.inputs:
@first(
  if(
    and(
      not(empty(variables('CompanyCode'))),
      greater(length(body('ByCompany1')), 0)
    ),
    body('ByCompany1'),
    body('ParseVendors1')?['value']
  )
)

ABN-DigitsOnly.inputs:
@replace(
  replace(
    replace(
      replace(
        replace(
          replace(outputs('ABN-Tidy'), 'ABN ', ''), 
          ' ', ''
        ),
        '-', ''
      ),
      '.', ''
    ),
    ',', ''
  ),
  decodeUriComponent('%C2%A0'), ''
)
